'use client';

import React, { useEffect, useState, useCallback } from 'react';
import dynamic from 'next/dynamic';
import { trainsApi, depotsApi, Train, Depot } from '@/lib/api';

// Train status types
type TrainStatus = 'available' | 'in-service' | 'maintenance';

interface TrainWithStatus extends Train {
  status: TrainStatus;
}

// Status colors
const statusColors: Record<TrainStatus, string> = {
  available: '#22c55e',    // green-500
  'in-service': '#3b82f6', // blue-500
  maintenance: '#ef4444',  // red-500
};

const statusLabels: Record<TrainStatus, string> = {
  available: 'Available',
  'in-service': 'In Service',
  maintenance: 'Maintenance',
};

// Dynamically import the map component to avoid SSR issues
const MapWithNoSSR = dynamic(
  () => import('./MapContent'),
  {
    ssr: false,
    loading: () => (
      <div className="h-[600px] bg-gray-100 rounded-lg flex items-center justify-center">
        <div className="text-gray-500">Loading map...</div>
      </div>
    )
  }
);

interface FleetMapProps {
  onTrainSelect?: (train: TrainWithStatus) => void;
}

/**
 * Fleet Map Component
 *
 * Displays an interactive map of Portugal showing:
 * - Train positions with status-colored markers
 * - Depot locations with capacity indicators
 */
export function FleetMap({ onTrainSelect }: FleetMapProps) {
  const [trains, setTrains] = useState<TrainWithStatus[]>([]);
  const [depots, setDepots] = useState<(Depot & { trainCount: number })[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [lastUpdated, setLastUpdated] = useState<Date | null>(null);
  const [showDepots, setShowDepots] = useState(true);
  const [statusFilters, setStatusFilters] = useState<Record<TrainStatus, boolean>>({
    available: true,
    'in-service': true,
    maintenance: true,
  });

  const fetchData = useCallback(async () => {
    try {
      const [trainsRes, depotsRes] = await Promise.all([
        trainsApi.getAll(),
        depotsApi.getAll(),
      ]);

      if (trainsRes.error) throw new Error(trainsRes.error);
      if (depotsRes.error) throw new Error(depotsRes.error);

      // Add status to trains
      const trainsWithStatus: TrainWithStatus[] = (trainsRes.data?.trains || []).map((train) => {
        let status: TrainStatus = 'available';
        if (train.fitnessStatus === 'unfit') {
          status = 'maintenance';
        }
        return { ...train, status };
      });

      setTrains(trainsWithStatus);
      setDepots(depotsRes.data?.depots || []);
      setLastUpdated(new Date());
      setError(null);
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Failed to load map data');
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchData();
  }, [fetchData]);

  // Auto-refresh every 30 seconds
  useEffect(() => {
    const interval = setInterval(fetchData, 30000);
    return () => clearInterval(interval);
  }, [fetchData]);

  const toggleStatusFilter = (status: TrainStatus) => {
    setStatusFilters((prev) => ({ ...prev, [status]: !prev[status] }));
  };

  const filteredTrains = trains.filter((train) => statusFilters[train.status]);

  if (loading) {
    return (
      <div className="h-[600px] bg-gray-100 rounded-lg flex items-center justify-center animate-pulse">
        <div className="text-gray-500">Loading fleet data...</div>
      </div>
    );
  }

  if (error) {
    return (
      <div className="h-[600px] bg-red-50 rounded-lg flex items-center justify-center">
        <div className="text-red-600">
          <strong>Error:</strong> {error}
        </div>
      </div>
    );
  }

  return (
    <div className="space-y-4">
      {/* Controls */}
      <div className="flex flex-wrap items-center justify-between gap-4 bg-white rounded-lg p-4 shadow">
        {/* Status Filters */}
        <div className="flex items-center gap-4">
          <span className="text-sm font-medium text-gray-700">Filter:</span>
          {(Object.keys(statusFilters) as TrainStatus[]).map((status) => (
            <label key={status} className="flex items-center gap-2 cursor-pointer">
              <input
                type="checkbox"
                checked={statusFilters[status]}
                onChange={() => toggleStatusFilter(status)}
                className="rounded border-gray-300"
              />
              <span
                className="w-3 h-3 rounded-full"
                style={{ backgroundColor: statusColors[status] }}
              />
              <span className="text-sm text-gray-600">{statusLabels[status]}</span>
            </label>
          ))}
        </div>

        {/* Depot Toggle */}
        <label className="flex items-center gap-2 cursor-pointer">
          <input
            type="checkbox"
            checked={showDepots}
            onChange={(e) => setShowDepots(e.target.checked)}
            className="rounded border-gray-300"
          />
          <span className="text-sm text-gray-600">Show Depots</span>
        </label>

        {/* Refresh */}
        <div className="flex items-center gap-4">
          {lastUpdated && (
            <span className="text-xs text-gray-500">
              Last updated: {lastUpdated.toLocaleTimeString()}
            </span>
          )}
          <button
            onClick={fetchData}
            className="px-3 py-1 text-sm bg-primary-100 text-primary-700 rounded hover:bg-primary-200 transition-colors"
          >
            Refresh Now
          </button>
        </div>
      </div>

      {/* Map */}
      <MapWithNoSSR
        trains={filteredTrains}
        depots={showDepots ? depots : []}
        onTrainSelect={onTrainSelect}
        statusColors={statusColors}
        statusLabels={statusLabels}
      />

      {/* Legend */}
      <div className="flex items-center gap-6 bg-white rounded-lg p-3 shadow text-sm">
        <span className="font-medium text-gray-700">Legend:</span>
        {(Object.keys(statusColors) as TrainStatus[]).map((status) => (
          <div key={status} className="flex items-center gap-2">
            <span
              className="w-4 h-4 rounded-full"
              style={{ backgroundColor: statusColors[status] }}
            />
            <span className="text-gray-600">{statusLabels[status]}</span>
          </div>
        ))}
        <div className="flex items-center gap-2">
          <span className="w-4 h-4 rounded bg-gray-400" />
          <span className="text-gray-600">Depot</span>
        </div>
      </div>
    </div>
  );
}

