    23→   */
    24→  fastify.get('/gantt', async (request: FastifyRequest, reply: FastifyReply) => {
    25→    try {
    26→      // Get date range (4 weeks from today)
    27→      const startDate = new Date();
    28→      startDate.setHours(0, 0, 0, 0);
    29→      const endDate = new Date(startDate);
    30→      endDate.setDate(endDate.getDate() + 28);
    31→
    32→      const startDateStr = startDate.toISOString().split('T')[0];
    33→      const endDateStr = endDate.toISOString().split('T')[0];
    34→
    35→      // Get all trains with their relations
    36→      const trainsData = await db.query.trains.findMany({
    37→        with: {
    38→          fleet: true,
    39→          baseDepot: true,
    40→        },
    41→        limit: 50,
    42→        orderBy: [asc(schema.trains.trainId)],
    43→      });
    44→
    45→      // Get maintenance schedules in range
    46→      const schedules = await db.query.maintenanceSchedules.findMany({
    47→        where: and(
    48→          gte(schema.maintenanceSchedules.scheduledDate, startDateStr),
    49→          lte(schema.maintenanceSchedules.scheduledDate, endDateStr)
    50→        ),
    51→        with: {
    52→          depot: true,
    53→        },
    54→      });
    55→
    56→      // Build train rows with events
    57→      const trainRows = trainsData.map(train => ({
    58→        id: train.id,
    59→        trainId: train.trainId,
    60→        fleetName: train.fleet?.name || 'Unknown',
    61→        depotCode: train.baseDepot?.code || 'UNK',
    62→        events: schedules
    63→          .filter(s => s.trainId === train.id)
    64→          .map(s => ({
    65→            id: s.id,
    66→            trainId: train.id,
    67→            trainCode: train.trainId,
    68→            type: s.maintenanceType as 'PM1' | 'PM2' | 'HM' | 'OVH',
    69→            startDate: s.scheduledDate,
    70→            endDate: s.scheduledDate,
    71→            depotId: s.depotId,
    72→            depotName: s.depot?.name || 'Unknown',
    73→            kmAtMaintenance: train.currentKm || 0,
    74→          })),
    75→      }));
    76→
    77→      return {
    78→        trains: trainRows,
    79→        startDate: startDateStr,
    80→        endDate: endDateStr,
    81→      };
    82→    } catch (error) {
    83→      request.log.error(error);
    84→      return reply.status(500).send({ error: 'Failed to fetch gantt data' });
    85→    }
    86→  });
    87→
    88→  /**
    89→   * GET /api/maintenance/depot-capacity
    90→   * Returns weekly depot capacity utilization
    91→   */
    92→  fastify.get('/depot-capacity', async (request: FastifyRequest, reply: FastifyReply) => {
    93→    try {
    94→      // Get all depots
    95→      const depotsData = await db.query.depots.findMany({
    96→        orderBy: [asc(schema.depots.code)],
    97→      });
    98→
    99→      // Generate 4 weeks of data
   100→      const weeks: { week: string; start: string; end: string }[] = [];
   101→      const today = new Date();
   102→      today.setHours(0, 0, 0, 0);
   103→
   104→      for (let w = 0; w < 4; w++) {
   105→        const weekStart = new Date(today);
   106→        weekStart.setDate(today.getDate() + w * 7);
   107→        const weekEnd = new Date(weekStart);
   108→        weekEnd.setDate(weekStart.getDate() + 6);
   109→
   110→        weeks.push({
   111→          week: `Week ${w + 1}`,
   112→          start: weekStart.toISOString().split('T')[0],
   113→          end: weekEnd.toISOString().split('T')[0],
   114→        });
   115→      }
   116→
   117→      // Get all maintenance schedules in range
   118→      const allSchedules = await db.query.maintenanceSchedules.findMany({
   119→        where: and(
   120→          gte(schema.maintenanceSchedules.scheduledDate, weeks[0].start),
   121→          lte(schema.maintenanceSchedules.scheduledDate, weeks[3].end)
   122→        ),
   123→        with: {
   124→          train: true,
   125→        },
   126→      });
   127→
   128→      // Build capacity data
   129→      const capacityData: Array<{
   130→        depotId: string;
   131→        depotName: string;
   132→        depotCode: string;
   133→        week: string;
   134→        weekStart: string;
   135→        weekEnd: string;
   136→        scheduled: number;
   137→        capacity: number;
   138→        utilization: number;
   139→        trains: string[];
   140→      }> = [];
   141→
   142→      for (const depot of depotsData) {
   143→        for (const week of weeks) {
