   145→          const weekSchedules = allSchedules.filter(s =>
   146→            s.depotId === depot.id &&
   147→            s.scheduledDate >= week.start &&
   148→            s.scheduledDate <= week.end
   149→          );
   150→
   151→          // Get train codes
   152→          const trainCodes = weekSchedules
   153→            .map(s => s.train?.trainId || 'Unknown')
   154→            .filter((v, i, a) => a.indexOf(v) === i); // unique
   155→
   156→          // Capacity is simplified as max schedules per week
   157→          const capacity = Math.ceil((depot.capacityManhours || 100) / 20);
   158→          const utilization = capacity > 0 ? (weekSchedules.length / capacity) * 100 : 0;
   159→
   160→          capacityData.push({
   161→            depotId: depot.id,
   162→            depotName: depot.name,
   163→            depotCode: depot.code,
   164→            week: week.week,
   165→            weekStart: week.start,
   166→            weekEnd: week.end,
   167→            scheduled: weekSchedules.length,
   168→            capacity,
   169→            utilization: Math.round(utilization * 10) / 10,
   170→            trains: trainCodes,
   171→          });
   172→        }
   173→      }
   174→
   175→      return {
   176→        depots: depotsData.map(d => ({
   177→          id: d.id,
   178→          name: d.name,
   179→          code: d.code,
   180→          maxCapacity: Math.ceil((d.capacityManhours || 100) / 20),
   181→        })),
   182→        weeks,
   183→        data: capacityData,
   184→      };
   185→    } catch (error) {
   186→      request.log.error(error);
   187→      return reply.status(500).send({ error: 'Failed to fetch depot capacity' });
   188→    }
   189→  });
   190→
   191→  /**
   192→   * PUT /api/maintenance/schedule/:id
   193→   * Update a maintenance schedule (for drag-drop)
   194→   */
   195→  fastify.put<{ Params: ScheduleIdParams; Body: ScheduleUpdateBody }>(
   196→    '/schedule/:id',
   197→    async (request, reply) => {
   198→      try {
   199→        const { id } = request.params;
   200→        const { startDate } = request.body;
   201→
